// Merge Store Input (channel info) with Bark API response
const stored = $input.first().json || {};
const barkResponse = $json || {};
const audio_base64 = barkResponse.audio_base64 || '';
const sample_rate = barkResponse.sample_rate || 0;
const format = barkResponse.format || 'wav';

return [{
  json: {
    success: !!audio_base64,
    format: format,
    sample_rate: sample_rate,
    audio_size_bytes: audio_base64.length,
    timestamp: new Date().toISOString(),
    channel: stored.channel || '#general',
    text: stored.text || '',
    voice_preset: stored.voice_preset || 'v2/en_speaker_6',
    output_format: stored.output_format || 'wav'
  }
}];

// Process Bark response - merge with original webhook input
const body = $json || {};
const audio_base64 = body.audio_base64 || '';
const sample_rate = body.sample_rate || 0;
const format = body.format || 'wav';

// Access stored input values via $('Store Input') to ensure access to original webhook payload
const stored = $('Store Input').first().json || {};

return [{
  json: {
    success: !!audio_base64,
    format: format,
    sample_rate: sample_rate,
    audio_size_bytes: audio_base64.length,
    timestamp: new Date().toISOString(),
    channel: stored.channel || '#general',
    text: stored.text || '',
    voice_preset: stored.voice_preset || 'v2/en_speaker_6',
    output_format: stored.output_format || 'wav'
  }
}];
